import { jsonrepair } from "jsonrepair";
export function isJsonFile(path, name) {
  return path.endsWith(".json") || name.endsWith(".json");
}
function tryParseJson(content) {
  try {
    const data = JSON.parse(content);
    return { valid: true, data };
  } catch (err) {
    return { valid: false, error: err instanceof Error ? err.message : String(err) };
  }
}
function repairJson(content) {
  try {
    const repaired = jsonrepair(content);
    JSON.parse(repaired);
    return repaired;
  } catch {
    return null;
  }
}
function formatError(content, rawError) {
  const lines = content.split(/\r?\n/);
  let errorLine = null;
  let errorCol = null;
  const posMatch = rawError.match(/at position (\d+)/);
  if (posMatch) {
    const position = parseInt(posMatch[1], 10);
    let offset = 0;
    for (let i = 0; i < lines.length; i++) {
      const lineLen = lines[i].length + 1;
      if (offset + lineLen > position) {
        errorLine = i;
        errorCol = position - offset;
        break;
      }
      offset += lineLen;
    }
  }
  let out = `JSON Syntax Error: ${rawError}

`;
  const contextRadius = 3;
  const startLine = errorLine !== null ? Math.max(0, errorLine - contextRadius) : 0;
  const endLine = errorLine !== null ? Math.min(lines.length - 1, errorLine + contextRadius) : lines.length - 1;
  const padWidth = String(endLine + 1).length;
  for (let i = startLine; i <= endLine; i++) {
    const lineNum = String(i + 1).padStart(padWidth, " ");
    const marker = i === errorLine ? " \u2190 ERROR" : "";
    out += `${lineNum}|${lines[i]}${marker}
`;
    if (i === errorLine && errorCol !== null) {
      out += `${" ".repeat(padWidth + 1 + errorCol)}^
`;
    }
  }
  return out;
}
export function validateOrRepairJson(content) {
  const parsed = tryParseJson(content);
  if (parsed.valid === false) {
    const repaired = repairJson(content);
    if (repaired !== null) {
      return { valid: true, data: JSON.parse(repaired), repaired: true, content: repaired };
    }
    return { valid: false, error: formatError(content, parsed.error) };
  }
  return { valid: true, data: parsed.data, repaired: false, content };
}
